var results = $.steps.fetchPosts.response.results || [];
var posts = results.map(function(page, i) {
  var props = page.properties || {};
  var title = '';
  if (props.Title && props.Title.title && props.Title.title.length > 0) {
    title = props.Title.title.map(function(t) { return t.plain_text || ''; }).join('');
  }
  if (!title && props.Name && props.Name.title && props.Name.title.length > 0) {
    title = props.Name.title.map(function(t) { return t.plain_text || ''; }).join('');
  }
  var content = '';
  if (props.Content && props.Content.rich_text) {
    content = props.Content.rich_text.map(function(t) { return t.plain_text || ''; }).join('');
  }
  var scheduledDate = '';
  if (props.ScheduledDate && props.ScheduledDate.date) {
    scheduledDate = props.ScheduledDate.date.start || '';
  }
  return { index: i + 1, title: title, content: content, scheduledDate: scheduledDate, pageId: page.id };
});
var postList = '';
posts.forEach(function(p) {
  postList += 'Post ' + p.index + ':\n';
  postList += '  Title: ' + p.title + '\n';
  postList += '  Content: ' + p.content.slice(0, 500) + '\n';
  postList += '  Date: ' + p.scheduledDate + '\n\n';
});
return { posts: posts, postList: postList, postCount: posts.length };

var data = $.steps.extractPosts.output;
var prompt = 'You are a LinkedIn content strategist. Transform the following draft posts into polished, engaging LinkedIn posts.

';
prompt += 'DRAFT POSTS (' + data.postCount + '):
' + data.postList + '
';
prompt += 'INSTRUCTIONS:
';
prompt += '- Optimize each post for LinkedIn engagement
';
prompt += '- Add a strong hook in the first line
';
prompt += '- Use short paragraphs and line breaks for readability
';
prompt += '- Include relevant hashtags (3-5 per post)
';
prompt += '- Add a call-to-action at the end
';
prompt += '- Keep each post under 1300 characters

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "posts": [
';
prompt += '    {
';
prompt += '      "originalTitle": "...",
';
prompt += '      "linkedinPost": "Full formatted LinkedIn post text",
';
prompt += '      "hashtags": ["#tag1", "#tag2"],
';
prompt += '      "estimatedEngagement": "High|Medium|Low",
';
prompt += '      "bestTimeToPost": "e.g. Tuesday 9am EST"
';
prompt += '    }
';
prompt += '  ]
';
prompt += '}';
return { prompt: prompt };

let raw = $.steps.aiOptimize.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { posts: [{ originalTitle: 'Draft', linkedinPost: raw, hashtags: [], estimatedEngagement: 'Medium', bestTimeToPost: '' }] }; }

var ai = $.steps.parseAI.output;
var posts = ai.posts || [];
var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'LinkedIn Posts Ready for Review', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + posts.length + ' post(s)* from Notion, optimized for LinkedIn' } });
blocks.push({ type: 'divider' });
posts.forEach(function(p, i) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Post ' + (i + 1) + ': ' + (p.originalTitle || 'Untitled') + '*\nEngagement: ' + (p.estimatedEngagement || '') + ' | Best time: ' + (p.bestTimeToPost || 'anytime') } });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: p.linkedinPost.slice(0, 2500) } });
  if (p.hashtags && p.hashtags.length > 0) {
    blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: p.hashtags.join(' ') }] });
  }
  blocks.push({ type: 'divider' });
});
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Generated from Notion via Claude AI + One CLI' }] });
var fallback = posts.length + ' LinkedIn post(s) ready for review';
return { blocks: blocks, fallback: fallback };
